import sys
from collections import deque

class TreeNode:
    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None

class Solution:
    def solve(self, root: TreeNode) -> int:
        if not root:
            return 0
        max_width = 0
        q = deque([root])
        while q:
            level_size = len(q)
            max_width = max(max_width, level_size)
            for _ in range(level_size):
                node = q.popleft()
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
        return max_width

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    # build tree from level order where "null" denotes missing node
    vals = data
    # first value is root
    root_val = vals[0]
    if root_val == 'null':
        print(0)
        sys.exit(0)
    root = TreeNode(int(root_val))
    q = deque([root])
    i = 1
    while q and i < len(vals):
        node = q.popleft()
        # left child
        if i < len(vals):
            val = vals[i]
            i += 1
            if val != 'null':
                node.left = TreeNode(int(val))
                q.append(node.left)
        # right child
        if i < len(vals):
            val = vals[i]
            i += 1
            if val != 'null':
                node.right = TreeNode(int(val))
                q.append(node.right)
    sol = Solution()
    print(sol.solve(root))

