#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    int solve(TreeNode* root) {
        if (!root) return 0;
        int maxWidth = 0;
        queue<TreeNode*> q;
        q.push(root);
        while (!q.empty()) {
            int sz = q.size();
            maxWidth = max(maxWidth, sz);
            for (int i = 0; i < sz; ++i) {
                TreeNode* node = q.front(); q.pop();
                if (node->left) q.push(node->left);
                if (node->right) q.push(node->right);
            }
        }
        return maxWidth;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    vector<string> vals;
    string token;
    while (cin >> token) {
        vals.push_back(token);
    }
    if (vals.empty()) return 0;
    // build tree from level order, "null" means no node
    if (vals[0] == "null") {
        cout << 0 << "\n";
        return 0;
    }
    TreeNode* root = new TreeNode(stoi(vals[0]));
    queue<TreeNode*> q;
    q.push(root);
    size_t i = 1;
    while (!q.empty() && i < vals.size()) {
        TreeNode* node = q.front(); q.pop();
        // left child
        if (i < vals.size()) {
            if (vals[i] != "null") {
                TreeNode* left = new TreeNode(stoi(vals[i]));
                node->left = left;
                q.push(left);
            }
            ++i;
        }
        // right child
        if (i < vals.size()) {
            if (vals[i] != "null") {
                TreeNode* right = new TreeNode(stoi(vals[i]));
                node->right = right;
                q.push(right);
            }
            ++i;
        }
    }
    Solution sol;
    cout << sol.solve(root) << "\n";
    return 0;
}
